export function htmlToNodes(string){const tmp=document.createElement("template");tmp.innerHTML=string;return tmp.content}export function interleave(arr,x){return arr.flatMap((e)=>[e,x]).slice(0,-1)}export const el=(tag,arg1,arg2)=>{const element=document.createElement(tag);let props={},children=[];if(arg1!==undefined&&arg1!==null&&(Array.isArray(arg1)||typeof arg1==="string"||typeof arg1==="number"||arg1 instanceof Node)){children=arg1}else{props=arg1||{};children=arg2||[]}for(const[key,val]of Object.entries(props)){if(val===undefined||val===null){continue}if(key.startsWith("on")&&typeof val==="function"){element.addEventListener(key.substring(2).toLowerCase(),val)}else if(key==="className"||key==="classList"||key==="class"){if(Array.isArray(val)){element.className=val.filter(Boolean).join(" ")}else if(typeof val==="string"){element.className=val}}else if(key==="dataset"&&typeof val==="object"){for(const[dataKey,dataVal]of Object.entries(val)){element.dataset[dataKey]=dataVal}}else if(key==="style"&&typeof val==="object"){Object.assign(element.style,val)}else{if(key in element){element[key]=val}else{element.setAttribute(key,val)}}}const append=(c)=>{if(c===undefined||c===null||c===false){return}if(Array.isArray(c)){c.forEach(append)}else if(c instanceof Node){element.appendChild(c)}else{element.appendChild(document.createTextNode(String(c)))}};append(children);return element};